import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
function Navbar(){
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');
  const navigate = useNavigate();
  const logout = ()=>{ localStorage.clear(); navigate('/login'); };
  return (
    <header className="bg-white shadow-md p-4 flex justify-between items-center">
      <h1 className="text-xl font-bold text-blue-600"><Link to="/">DOCGUARD</Link></h1>
      <nav className="space-x-4">
        <Link to="/">Home</Link>
        {!token && <>
          <Link to="/login">Login</Link>
          <Link to="/signup">Register</Link>
        </>}
        {token && role==='user' && <>
          <Link to="/dashboard">Dashboard</Link>
          <Link to="/downloads">My Downloads</Link>
          <Link to="/request-access">Request Access</Link>
          <Link to="/pending-requests">Pending Requests</Link>
          <Link to="/logs">My Logs</Link>
        </>}
        {token && role==='admin' && <Link to="/admin">Admin</Link>}
        <Link to="/contact">Contact</Link>
        <Link to="/feedback">Feedback</Link>
        {token && <button onClick={logout} className="bg-red-500 text-white px-3 py-1 rounded">Logout</button>}
      </nav>
    </header>
  );
}
export default Navbar;
